VALUES
  ('optometrist-moex-01214', 'optometrist', 'optometrist-moex-110-ddcf1380', 'sub-optometrist-04', NULL, 'single_choice', '開立一個聚碳酸酯的鏡片處方，如果鏡片的光學中心與患者的瞳孔未對準時，下列何者最可能導致視力下 降？', '["球面像差", "彗星像差", "縱向色像差", "橫向色像差"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:46+00:00", "source_pdf_sha1": "0b4912735e4c", "answer_pdf_sha1": "c510c33b9b6c", "source_family": "moex-gov-tw", "moex": {"exam_code": "110111", "c": "112", "s": "1102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "視覺光學", "year": "110", "exam_name": "第二梯次:110年第二次專技人員高等考試中醫師考試分階段考試、營養師、社會工作師考試、110年專技人員高等考試心理師、法醫師、語言治療師、聽...", "original_question_number": 47, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-01215', 'optometrist', 'optometrist-moex-110-ddcf1380', 'sub-optometrist-04', NULL, 'single_choice', '一個病患有屈光不正，右眼-4.00D，左眼-9.00D，經過角膜曲率鏡測量後，初步判定兩眼角膜有相同屈光 力，下列敘述何者正確？', '["此病患的兩眼不等視最有可能是屬於軸性", "此病患的兩眼不等視最有可能是屬於屈光性", "此病患戴上眼鏡完全矯正，左眼看到的影像較大", "此病患戴上隱形眼鏡後，就不會有兩眼不等像的問題"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:46+00:00", "source_pdf_sha1": "0b4912735e4c", "answer_pdf_sha1": "c510c33b9b6c", "source_family": "moex-gov-tw", "moex": {"exam_code": "110111", "c": "112", "s": "1102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "視覺光學", "year": "110", "exam_name": "第二梯次:110年第二次專技人員高等考試中醫師考試分階段考試、營養師、社會工作師考試、110年專技人員高等考試心理師、法醫師、語言治療師、聽...", "original_question_number": 48, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-01216', 'optometrist', 'optometrist-moex-110-ddcf1380', 'sub-optometrist-04', NULL, 'single_choice', '高度近視的病患常抱怨配戴眼鏡時感到光線較暗，其原因最不可能為下列何者？', '["使用高折射率鏡片", "鏡片較薄", "鏡片鍍膜", "鏡片材質的光線吸收度太高"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:46+00:00", "source_pdf_sha1": "0b4912735e4c", "answer_pdf_sha1": "c510c33b9b6c", "source_family": "moex-gov-tw", "moex": {"exam_code": "110111", "c": "112", "s": "1102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "視覺光學", "year": "110", "exam_name": "第二梯次:110年第二次專技人員高等考試中醫師考試分階段考試、營養師、社會工作師考試、110年專技人員高等考試心理師、法醫師、語言治療師、聽...", "original_question_number": 49, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-01217', 'optometrist', 'optometrist-moex-110-ddcf1380', 'sub-optometrist-04', NULL, 'single_choice', '有關鏡片造成彗星像差的敘述，下列何者錯誤？', '["彗星像差是拋物面鏡與生俱來，不可避免", "消除彗星像差的方法，可以利用遠離光軸位置部分，適度調整曲率半徑而達成", "彗星像差的大小，與鏡片的直徑平方成正比", "彗星像差是指離軸平行光線會形成一模糊的光斑"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:46+00:00", "source_pdf_sha1": "0b4912735e4c", "answer_pdf_sha1": "c510c33b9b6c", "source_family": "moex-gov-tw", "moex": {"exam_code": "110111", "c": "112", "s": "1102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "視覺光學", "year": "110", "exam_name": "第二梯次:110年第二次專技人員高等考試中醫師考試分階段考試、營養師、社會工作師考試、110年專技人員高等考試心理師、法醫師、語言治療師、聽...", "original_question_number": 50, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-01218', 'optometrist', 'optometrist-moex-110-28e89c47', 'sub-optometrist-05', NULL, 'single_choice', '有關軟式隱形眼鏡材質的敘述，下列何者錯誤？', '["聚甲基丙烯酸甲酯（polymethyl methacrylate, PMMA）結合羥基（OH）後，形成聚甲基丙烯酸乙酯 （polyhydroxyethylmethacrylate,pHEMA）的聚合物材質", "聚甲基丙烯酸乙酯比甲基丙烯酸甘油酯（glycerylmethacrylate,GMA）材質有更大的親水性", "乙酸丁酸纖維素（celluloseacetatebutyrate,CAB）不是製作軟式隱形眼鏡的材質", "聚甲基丙烯酸乙酯材質因含有羥基，所以有很好的濕潤性"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:46+00:00", "source_pdf_sha1": "9f4b5d5e89b6", "answer_pdf_sha1": "8ffbde5a34ce", "source_family": "moex-gov-tw", "moex": {"exam_code": "110111", "c": "112", "s": "1104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學與配鏡學", "year": "110", "exam_name": "第二梯次:110年第二次專技人員高等考試中醫師考試分階段考試、營養師、社會工作師考試、110年專技人員高等考試心理師、法醫師、語言治療師、聽...", "original_question_number": 1, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-01219', 'optometrist', 'optometrist-moex-110-28e89c47', 'sub-optometrist-05', NULL, 'single_choice', '由於鏡片表面濕潤性（surfacewettability）和規格穩定性（dimensionalstability）的好處，下列那一分類的 鏡片已成為大多數近視日戴型RGP最常選用的材料？', '["低Dk之氟矽丙烯酸酯（fluoro-silicone/acrylate,F-S/A）", "低Dk之乙酸丁酸纖維素（celluloseacetatebutyrate）", "低Dk之甲基丙烯酸甘油酯（glycerylmethacrylate）", "高Dk之矽氧烷丙烯酸酯（silicone/acrylate,S/A）"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:46+00:00", "source_pdf_sha1": "9f4b5d5e89b6", "answer_pdf_sha1": "8ffbde5a34ce", "source_family": "moex-gov-tw", "moex": {"exam_code": "110111", "c": "112", "s": "1104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學與配鏡學", "year": "110", "exam_name": "第二梯次:110年第二次專技人員高等考試中醫師考試分階段考試、營養師、社會工作師考試、110年專技人員高等考試心理師、法醫師、語言治療師、聽...", "original_question_number": 2, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-01220', 'optometrist', 'optometrist-moex-110-28e89c47', 'sub-optometrist-05', NULL, 'single_choice', '有關於軟式隱形眼鏡、硬式隱形眼鏡之比較，下列敘述何者正確？', '["主要影響硬式隱形眼鏡透氧率的因素是methylmethacrylate（MMA）的增加", "軟式隱形眼鏡在有散光角膜上一定會因為柔曲現象而有殘餘散光的出現", "硬式隱形眼鏡的折射率與刮擦程度（theextentofscratching）成負相關", "若無殘餘散光，軟式隱形眼鏡比硬式隱形眼鏡有較佳的光學透明度"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:46+00:00", "source_pdf_sha1": "9f4b5d5e89b6", "answer_pdf_sha1": "8ffbde5a34ce", "source_family": "moex-gov-tw", "moex": {"exam_code": "110111", "c": "112", "s": "1104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學與配鏡學", "year": "110", "exam_name": "第二梯次:110年第二次專技人員高等考試中醫師考試分階段考試、營養師、社會工作師考試、110年專技人員高等考試心理師、法醫師、語言治療師、聽...", "original_question_number": 3, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-01221', 'optometrist', 'optometrist-moex-110-28e89c47', 'sub-optometrist-05', NULL, 'single_choice', '有關隱形眼鏡鏡片，下列敘述何者正確？', '["水膠隨著含水量的增加，透鏡強度和抗沉積物能力降低，並且透氧性隨著含水量的增加而減少", "根據HarvittandBonanno（1999）的研究，關於過夜配戴型角膜塑型鏡片，為避免整層角膜水腫DK/L最 少需85", "老一代矽水膠鏡片，雖然透氧性非常高，但具有較大的彈性模量（modulusofelasticity），導致淺表上皮 角膜弓狀病變（superficialepithelialarcuatelesions,SEALs），粘蛋白球（musin）沉積物和隱形眼鏡乳突 狀結膜炎（contact-lens-inducedpapillaryconjunctivitis,CLPC）的發生率更高", "較新的矽水膠與早期的矽水膠相比，它們具有較低的含水量，較高的模數並且不需要進行表面處理"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:46+00:00", "source_pdf_sha1": "9f4b5d5e89b6", "answer_pdf_sha1": "8ffbde5a34ce", "source_family": "moex-gov-tw", "moex": {"exam_code": "110111", "c": "112", "s": "1104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學與配鏡學", "year": "110", "exam_name": "第二梯次:110年第二次專技人員高等考試中醫師考試分階段考試、營養師、社會工作師考試、110年專技人員高等考試心理師、法醫師、語言治療師、聽...", "original_question_number": 4, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-01222', 'optometrist', 'optometrist-moex-110-28e89c47', 'sub-optometrist-05', NULL, 'single_choice', '下列何者不是硬式鏡片常用的濕潤劑（wettingagents）？', '["甲基丙烯酸（methacrylicacid,MAA）", "聚乙烯醇（polyvinylalcohol,PVA）", "乙烯基吡咯烷酮（N-vinylpyrrolidone,NVP）", "乙二醇二甲基丙烯酸酯（ethyleneglycoldimethacrylate,EGDMA）"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:46+00:00", "source_pdf_sha1": "9f4b5d5e89b6", "answer_pdf_sha1": "8ffbde5a34ce", "source_family": "moex-gov-tw", "moex": {"exam_code": "110111", "c": "112", "s": "1104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學與配鏡學", "year": "110", "exam_name": "第二梯次:110年第二次專技人員高等考試中醫師考試分階段考試、營養師、社會工作師考試、110年專技人員高等考試心理師、法醫師、語言治療師、聽...", "original_question_number": 5, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-01223', 'optometrist', 'optometrist-moex-110-28e89c47', 'sub-optometrist-05', NULL, 'single_choice', '甲基丙烯酸羥乙酯（2-hydroxyethylmethacrylate,HEMA）與甲基丙烯酸甘油酯（glycerylmethacrylate,GMA） 材質結合時，下列敘述何者正確？', '["低含水離子性鏡片", "對pH值變化敏感", "EtafilconA不屬於這類材質", "FDA分類中的第四類材質"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:46+00:00", "source_pdf_sha1": "9f4b5d5e89b6", "answer_pdf_sha1": "8ffbde5a34ce", "source_family": "moex-gov-tw", "moex": {"exam_code": "110111", "c": "112", "s": "1104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學與配鏡學", "year": "110", "exam_name": "第二梯次:110年第二次專技人員高等考試中醫師考試分階段考試、營養師、社會工作師考試、110年專技人員高等考試心理師、法醫師、語言治療師、聽...", "original_question_number": 6, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL)
